const base = env.get('CALIBRE_URL');
const user = env.get('CALIBRE_USER');
const pass = env.get('CALIBRE_PASSWORD');
if (!user || !pass) { node.error('CALIBRE_USER or CALIBRE_PASSWORD not set'); return null; }
const { query, limit } = msg.payload;
msg._limit = limit || 10;
msg.url = `${base}/opds/search/${encodeURIComponent(query)}`;
msg.headers = { 'Authorization': 'Basic ' + Buffer.from(`${user}:${pass}`).toString('base64') };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const xml = msg.payload;
const lim = msg._limit || 10;
const entries = [...xml.matchAll(/<entry>([\s\S]*?)<\/entry>/g)];
const books = entries
  .filter(([, e]) => /\/download\//.test(e))
  .slice(0, lim)
  .map(([, e]) => {
    const txt = tag => {
      const m = e.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`));
      return m ? m[1].replace(/<[^>]+>/g, '').trim() : null;
    };
    const rawId = txt('id') || '';
    const bookId = rawId.match(/\/(\d+)(?:\/|$)/)?.[1];
    const formats = [...e.matchAll(/\/download\/\d+\/([a-z0-9]+)/gi)].map(m => m[1].toUpperCase());
    return {
      id: bookId ? parseInt(bookId) : null,
      title: txt('title'),
      author: txt('name'),
      added: txt('updated') || null,
      summary: (txt('content') || txt('summary') || '').slice(0, 200) || null,
      formats: [...new Set(formats)]
    };
  });
msg.payload = JSON.stringify(books);
return msg;

