const base = env.get('CALIBRE_URL');
const user = env.get('CALIBRE_USER');
const pass = env.get('CALIBRE_PASSWORD');
if (!user || !pass) { node.error('CALIBRE_USER or CALIBRE_PASSWORD not set'); return null; }
const { book_id } = msg.payload;

let session = flow.get('calibre_session');
const expires = flow.get('calibre_session_expires') || 0;

if (!session || Date.now() > expires) {
  const formBody = new URLSearchParams({ username: user, password: pass, next: '/', remember_me: 'on' }).toString();
  const u = new URL(`${base}/login`);
  session = await new Promise((resolve, reject) => {
    const req = http.request({
      hostname: u.hostname,
      port: parseInt(u.port) || 80,
      path: '/login',
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Content-Length': Buffer.byteLength(formBody)
      }
    }, res => {
      res.resume();
      const cookie = (res.headers['set-cookie'] || []).find(c => c.startsWith('session='));
      resolve(cookie ? cookie.split(';')[0] : null);
    });
    req.on('error', reject);
    req.setTimeout(5000, () => { req.destroy(); reject(new Error('login timeout')); });
    req.write(formBody);
    req.end();
  });
  if (!session) { node.error('Calibre-Web login failed — check CALIBRE_USER and CALIBRE_PASSWORD'); return null; }
  flow.set('calibre_session', session);
  flow.set('calibre_session_expires', Date.now() + 3600000);
}

msg.url = `${base}/ajax/toggleread/${book_id}`;
msg.headers = { 'Cookie': session, 'X-Requested-With': 'XMLHttpRequest' };
msg.payload = {};
return msg;

if (msg.statusCode === 401 || msg.statusCode === 403) {
  flow.set('calibre_session', null);
  msg.payload = JSON.stringify({ error: 'Auth failed — session cleared, retry' });
  return msg;
}
if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const r = typeof msg.payload === 'object' ? msg.payload : {};
msg.payload = JSON.stringify({ success: true, read: r.read ?? null });
return msg;

